1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return no living cells when given no living cells", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single living cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill a living cell with only one living neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a living cell alive with two living neighbors", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [2, 0]])).toContainEqual([1, 0]);
16	  });
17	  it("should keep a living cell alive with three living neighbors", () => {
18	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]])).toContainEqual([1, 0]);
19	  });
20	  it("should kill a living cell with more than three living neighbors (overpopulation)", () => {
21	    expect(nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]])).not.toContainEqual([1, 1]);
22	  });
23	  it("should bring a dead cell to life with exactly three living neighbors (reproduction)", () => {
24	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
25	  });
26	  it.todo("should handle living cells at negative coordinates");
27	});
28

1	export type Cell = [number, number];
2	
3	const isNeighbor = ([x1, y1]: Cell, [x2, y2]: Cell): boolean => {
4	  const dx = Math.abs(x1 - x2);
5	  const dy = Math.abs(y1 - y2);
6	  const isSameCell = dx === 0 && dy === 0;
7	  return !isSameCell && dx <= 1 && dy <= 1;
8	};
9	
10	const countLivingNeighbors = (cell: Cell, livingCells: Cell[]): number =>
11	  livingCells.filter((other) => isNeighbor(cell, other)).length;
12	
13	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
14	
15	const getCandidateCells = (livingCells: Cell[]): Cell[] => {
16	  const candidates = new Map<string, Cell>();
17	  for (const [x, y] of livingCells) {
18	    for (let dx = -1; dx <= 1; dx++) {
19	      for (let dy = -1; dy <= 1; dy++) {
20	        const candidate: Cell = [x + dx, y + dy];
21	        candidates.set(cellKey(candidate), candidate);
22	      }
23	    }
24	  }
25	  return Array.from(candidates.values());
26	};
27	
28	const livesInNextGeneration = (cell: Cell, livingCells: Cell[]): boolean => {
29	  const neighbors = countLivingNeighbors(cell, livingCells);
30	  const isAlive = livingCells.some((living) => cellKey(living) === cellKey(cell));
31	  return isAlive ? neighbors === 2 || neighbors === 3 : neighbors === 3;
32	};
33	
34	export const nextGeneration = (livingCells: Cell[]): Cell[] =>
35	  getCandidateCells(livingCells).filter((cell) => livesInNextGeneration(cell, livingCells));
